// and João Ferreira de Almeida (Almeida, PT), via seven1m/open-bibles (USFX).
// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'micah',
  name: 'Miquéias',
  englishName: 'Micah',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'Yahweh’s word that came to Micah the Morashtite in the days of Jotham, Ahaz, and Hezekiah, kings of Judah, which he saw concerning Samaria and Jerusalem.', pt: 'A palavra do Senhor que veio a Miquéias, morastita, nos dias de Jotão Acaz e Ezequias reis de Judá a qual ele viu sobre Samária e Jerusalém.' },
      { v: 2, en: 'Hear, you peoples, all of you. Listen, O earth, and all that is therein: and let the Lord Yahweh be witness against you, the Lord from his holy temple.', pt: 'Ouvi, todos os povos; presta atenção, ó terra, e tudo o que nela há; e seja testemunha contra vós o Senhor Deus, o Senhor desde o seu santo templo.' },
      { v: 3, en: 'For, behold, Yahweh comes out of his place, and will come down and tread on the high places of the earth.', pt: 'Porque eis que o Senhor está a sair do seu lugar, e descerá, e andará sobre as alturas da terra.' },
      { v: 4, en: 'The mountains melt under him, and the valleys split apart, like wax before the fire, like waters that are poured down a steep place.', pt: 'Os montes debaixo dele se derreterão, e os vales se fenderão, como a cera diante do fogo, como as águas que se precipitam por um declive.' },
      { v: 5, en: '“All this is for the disobedience of Jacob, and for the sins of the house of Israel. What is the disobedience of Jacob? Isn’t it Samaria? And what are the high places of Judah? Aren’t they Jerusalem?', pt: 'Sucede tudo isso por causa da transgressão de Jacó, e por causa dos pecados da casa de Israel. Qual é a transgressão de Jacó? não é Samária? e quais os altos de Judá? não é Jerusalém?' },
      { v: 6, en: 'Therefore I will make Samaria like a rubble heap of the field, like places for planting vineyards; and I will pour down its stones into the valley, and I will uncover its foundations.', pt: 'Por isso farei de Samária um montão de pedras do campo, uma terra de plantar vinhas; e farei rebolar as suas pedras para o vale, e descobrirei os seus fundamentos.' },
      { v: 7, en: 'All her idols will be beaten to pieces, and all her temple gifts will be burned with fire, and all her images I will destroy; for of the hire of a prostitute has she gathered them, and to the hire of a prostitute shall they return.”', pt: 'Todas as suas imagens esculpidas serão despedaçadas, todos os seus salários serão queimados pelo fogo, e de todos os seus ídolos farei uma assolação; porque pelo salário de prostituta os ajuntou, e em salário de prostituta se tornarão.' },
      { v: 8, en: 'For this I will lament and wail; I will go stripped and naked; I will howl like the jackals, and moan like the daughters of owls.', pt: 'Por isso lamentarei e uivarei, andarei despojado e nu farei lamentação como de chacais, e pranto como de avestruzes.' },
      { v: 9, en: 'For her wounds are incurable; for it has come even to Judah. It reaches to the gate of my people, even to Jerusalem.', pt: 'Pois as suas feridas são incuráveis, e o mal chegou até Judá; estendeu-se até a porta do meu povo, até Jerusalém.' },
      { v: 10, en: 'Don’t tell it in Gath. Don’t weep at all. At Beth Ophrah I have rolled myself in the dust.', pt: 'Não o anuncieis em Gate, em Aco não choreis; em Bete-Le-Afra revolvei-vos no pó.' },
      { v: 11, en: 'Pass on, inhabitant of Shaphir, in nakedness and shame. The inhabitant of Zaanan won’t come out. The wailing of Beth Ezel will take from you his protection.', pt: 'Passa, ó moradora de Safir, em vergonhosa nudez; a moradora de Zaanã não saiu; o pranto de Bete-Ezel tomará de vós a sua morada.' },
      { v: 12, en: 'For the inhabitant of Maroth waits anxiously for good, because evil has come down from Yahweh to the gate of Jerusalem.', pt: 'Pois a moradora de Marote espera ansiosamente pelo bem; porque desceu do Senhor o mal até a porta de Jerusalém.' },
      { v: 13, en: 'Harness the chariot to the swift steed, inhabitant of Lachish. She was the beginning of sin to the daughter of Zion; For the transgressions of Israel were found in you.', pt: 'Ata ao carro o cavalo ligeiro, ó moradora de Laquis; esta foi o princípio do pecado para a filha de Sião; pois em ti se acharam as transgressões de Israel.' },
      { v: 14, en: 'Therefore you will give a parting gift to Moresheth Gath. The houses of Achzib will be a deceitful thing to the kings of Israel.', pt: 'Por isso darás a Moresete-Gate presentes de despedida; as casas de Aczibe se tornarão em engano para os reis de Israel.' },
      { v: 15, en: 'I will yet bring to you, inhabitant of Mareshah. He who is the glory of Israel will come to Adullam.', pt: 'Ainda trarei a ti, o moradora de Maressa, aquele que te possuirá; chegará até Adulão a glória de Israel.' },
      { v: 16, en: 'Shave your heads, and cut off your hair for the children of your delight. Enlarge your baldness like the vulture; for they have gone into captivity from you!', pt: 'Faze-te calva e tosquia-te por causa dos filhos das tuas delícias; alarga a tua calva como a águia, porque de ti serão levados para o cativeiro.' },
    ],
    2: [
      { v: 1, en: 'Woe to those who devise iniquity and work evil on their beds! When the morning is light, they practice it, because it is in the power of their hand.', pt: 'Ai daqueles que nas suas camas maquinam a iniqüidade e planejam o mal! quando raia o dia, põem-no por obra, pois está no poder da sua mão.' },
      { v: 2, en: 'They covet fields, and seize them; and houses, and take them away: and they oppress a man and his house, even a man and his heritage.', pt: 'E cobiçam campos, e os arrebatam, e casas, e as tomam; assim fazem violência a um homem e à sua casa, a uma pessoa e à sua herança.' },
      { v: 3, en: 'Therefore Yahweh says: “Behold, I am planning against these people a disaster, from which you will not remove your necks, neither will you walk haughtily; for it is an evil time.', pt: 'Portanto, assim diz o Senhor. Eis que contra esta família maquino um mal, de que não retirareis os vossos pescoços; e não andareis arrogantemente; porque o tempo sera mau.' },
      { v: 4, en: 'In that day they will take up a parable against you, and lament with a doleful lamentation, saying, ‘We are utterly ruined! My people’s possession is divided up. Indeed he takes it from me and assigns our fields to traitors!’”', pt: 'Naquele dia surgirá contra vós um motejo, e se levantará pranto lastimoso, dizendo: Nós estamos inteiramente despojados; a porção do meu povo ele a troca; como ele a remove de mim! aos rebeldes reparte os nossos campos.' },
      { v: 5, en: 'Therefore you will have no one who divides the land by lot in Yahweh’s assembly.', pt: 'Portanto, não terás tu na cogregação do Senhor quem lance o cordel pela sorte' },
      { v: 6, en: '“Don’t prophesy!” They prophesy. “Don’t prophesy about these things. Disgrace won’t overtake us.”', pt: 'Não profetizeis; assim profetizam eles, - não se deve profetizar tais coisas; não nos alcançará o opróbrio.' },
      { v: 7, en: 'Shall it be said, O house of Jacob: “Is Yahweh’s Spirit angry? Are these his doings? Don’t my words do good to him who walks blamelessly?”', pt: 'Acaso dir-se-á isso, ó casa de Jacó: tem-se restringido o Espírito do Senhor? são estas as suas obras? e não é assim que fazem bem as minhas palavras ao que anda retamente?' },
      { v: 8, en: 'But lately my people have risen up as an enemy. You strip the robe and clothing from those who pass by without a care, returning from battle.', pt: 'Mas há pouco se levantou o meu povo como um inimigo; de sobre a vestidura arrancais o manto aos que passam seguros, como homens contrários à guerra.' },
      { v: 9, en: 'You drive the women of my people out from their pleasant houses; from their young children you take away my blessing forever.', pt: 'As mulheres do meu povo, vós as lançais das suas casas agradáveis; dos seus filhinhos tirais para sempre a minha glória.' },
      { v: 10, en: 'Arise, and depart! For this is not your resting place, because of uncleanness that destroys, even with a grievous destruction.', pt: 'Levantai-vos, e ide-vos, pois este não é lugar de descanso; por causa da imundícia que traz destruição, sim, destruição enorme.' },
      { v: 11, en: 'If a man walking in a spirit of falsehood lies: “I will prophesy to you of wine and of strong drink”; he would be the prophet of this people.', pt: 'Se algum homem, andando em espírito de falsidade, mentir, dizendo: Eu te profetizarei acerca do vinho e da bebida forte; será esse tal o profeta deste povo.' },
      { v: 12, en: 'I will surely assemble, Jacob, all of you; I will surely gather the remnant of Israel; I will put them together as the sheep of Bozrah, as a flock in the middle of their pasture; they will swarm with people.', pt: 'Certamente te ajuntarei todo, ó Jacó; certamente congregarei o restante de Israel; pô-los-ei todos juntos, como ovelhas no curral, como rebanho no meio do seu pasto; farão estrondo por causa da multidão dos homens.' },
      { v: 13, en: 'He who breaks open the way goes up before them. They break through the gate, and go out. And their king passes on before them, with Yahweh at their head.', pt: 'Subirá diante deles aquele que abre o caminho; eles romperão, e entrarão pela porta, e sairão por ela; e o rei irá adiante deles, e o Senhor à testa deles.' },
    ],
    3: [
      { v: 1, en: 'I said, “Please listen, you heads of Jacob, and rulers of the house of Israel: Isn’t it for you to know justice?', pt: 'E disse eu: Ouvi, peço-vos, ó chefes de Jacó, e vós, ó príncipes da casa de Israel: não é a vós que pertence saber a justiça?' },
      { v: 2, en: 'You who hate the good, and love the evil; who tear off their skin, and their flesh from off their bones;', pt: 'A vós que aborreceis o bem, e amais o mal, que arrancais a pele de cima deles, e a carne de cima dos seus ossos,' },
      { v: 3, en: 'who also eat the flesh of my people, and flay their skin from off them, and break their bones, and chop them in pieces, as for the pot, and as meat within the cauldron.', pt: 'os que também comeis a carne do meu povo e lhes arrancais a pele, e lhes esmiuçais os ossos, e os repartis em pedaços como para a panela e como carne dentro do caldeirão.' },
      { v: 4, en: 'Then they will cry to Yahweh, but he will not answer them. Yes, he will hide his face from them at that time, because they made their deeds evil.”', pt: 'Então clamarão ao Senhor; ele, porém, não lhes responderá, antes esconderá deles a sua face naquele tempo, conforme eles fizeram mal nas suas obras.' },
      { v: 5, en: 'Yahweh says concerning the prophets who lead my people astray; for those who feed their teeth, they proclaim, “Peace!” and whoever doesn’t provide for their mouths, they prepare war against him:', pt: 'Assim diz o Senhor a respeito dos profetas que fazem errar o meu povo, que clamam: Paz! enquanto têm o que comer, mas preparam a guerra contra aquele que nada lhes mete na boca.' },
      { v: 6, en: '“Therefore night is over you, with no vision, and it is dark to you, that you may not divine; and the sun will go down on the prophets, and the day will be black over them.', pt: 'Portanto se vos fará noite sem visão; e trevas sem adivinhação haverá para vós. Assim se porá o sol sobre os profetas, e sobre eles, obscurecerá o dia.' },
      { v: 7, en: 'The seers shall be disappointed, and the diviners confounded. Yes, they shall all cover their lips; for there is no answer from God.”', pt: 'E os videntes se envergonharão, e os adivinhadores se confundirão; sim, todos eles cobrirão os seus lábios, porque não haverá resposta de Deus.' },
      { v: 8, en: 'But as for me, I am full of power by Yahweh’s Spirit, and of judgment, and of might, to declare to Jacob his disobedience, and to Israel his sin.', pt: 'Quanto a mim, estou cheio do poder do Espírito do Senhor, assim como de justiça e de coragem, para declarar a Jacó a sua transgressão e a Israel o seu pecado.' },
      { v: 9, en: 'Please listen to this, you heads of the house of Jacob, and rulers of the house of Israel, who abhor justice, and pervert all equity.', pt: 'Ouvi agora isto, vós chefes da casa de Jacó, e vós governantes da casa de Israel, que abominais a justiça e perverteis tudo o que é direito,' },
      { v: 10, en: 'They build up Zion with blood, and Jerusalem with iniquity.', pt: 'edificando a Sião com sangue, e a Jerusalém com iniqüidade.' },
      { v: 11, en: 'Her leaders judge for bribes, and her priests teach for a price, and her prophets of it tell fortunes for money: yet they lean on Yahweh, and say, “Isn’t Yahweh among us? No disaster will come on us.”', pt: 'Os seus chefes dão as sentenças por peitas, e os seus sacerdotes ensinam por interesse, e os seus profetas adivinham por dinheiro; e ainda se encostam ao Senhor, dizendo: Não está o Senhor no meio de nós? nenhum mal nos sobrevirá.' },
      { v: 12, en: 'Therefore Zion for your sake will be plowed like a field, and Jerusalem will become heaps of rubble, and the mountain of the temple like the high places of a forest.', pt: 'Portanto, por causa de vós, Sião será lavrada como um campo, e Jerusalém se tornará em montões de pedras, e o monte desta casa em lugares altos dum bosque.' },
    ],
    4: [
      { v: 1, en: 'But in the latter days, it will happen that the mountain of Yahweh’s temple will be established on the top of the mountains, and it will be exalted above the hills; and peoples will stream to it.', pt: 'Mas nos últimos dias acontecerá que o monte da casa do Senhor será estabelecido como o mais alto dos montes, e se exalçará sobre os outeiros, e a ele concorrão os povos.' },
      { v: 2, en: 'Many nations will go and say, “Come, and let us go up to the mountain of Yahweh, and to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths.” For the law will go out of Zion, and Yahweh’s word from Jerusalem;', pt: 'E irão muitas nações, e dirão: Vinde, e subamos ao monte do Senhor, e à casa do Deus de Jacó, para que nos ensine os seus caminhos, de sorte que andemos nas suas veredas; porque de Sião sairá a lei, e de Jerusalém a palavra do Senhor.' },
      { v: 3, en: 'and he will judge between many peoples, and will decide concerning strong nations afar off. They will beat their swords into plowshares, and their spears into pruning hooks. Nation will not lift up sword against nation, neither will they learn war any more.', pt: 'E julgará entre muitos povos, e arbitrará entre nações poderosas e longínquas; e converterão as suas espadas em relhas de arado, e as suas lanças em podadeiras; uma nação não levantará a espada contra outra nação, nem aprenderão mais a guerra.' },
      { v: 4, en: 'But they will sit every man under his vine and under his fig tree; and no one will make them afraid: For the mouth of Yahweh of Armies has spoken.', pt: 'Mas assentar-se-á cada um debaixo da sua videira, e debaixo da sua figueira, e não haverá quem os espante, porque a boca do Senhor dos exércitos o disse.' },
      { v: 5, en: 'Indeed all the nations may walk in the name of their gods; but we will walk in the name of Yahweh our God forever and ever.', pt: 'Pois todos os povos andam, cada um em nome do seu deus; mas nós andaremos para todo o sempre em o nome do Senhor nosso Deus.' },
      { v: 6, en: '“In that day,” says Yahweh, “I will assemble that which is lame, and I will gather that which is driven away, and that which I have afflicted;', pt: 'Naquele dia, diz o Senhor, congregarei a que coxeava, e recolherei a que tinha sido expulsa, e a que eu afligi.' },
      { v: 7, en: 'and I will make that which was lame a remnant, and that which was cast far off a strong nation: and Yahweh will reign over them on Mount Zion from then on, even forever.”', pt: 'E da que coxeava farei um resto, e da que tinha sido arrojada para longe, uma nação poderosa; e o Senhor reinará sobre eles no monte Sião, desde agora e para sempre.' },
      { v: 8, en: 'You, tower of the flock, the hill of the daughter of Zion, to you it will come, yes, the former dominion will come, the kingdom of the daughter of Jerusalem.', pt: 'E a ti, ó torre do rebanho, outeiro da filha de Sião, a ti virá, sim, a ti virá o primeiro domínio, o reino da filha de Jerusalém.' },
      { v: 9, en: 'Now why do you cry out aloud? Is there no king in you? Has your counselor perished, that pains have taken hold of you as of a woman in travail?', pt: 'E agora, por que fazes tão grande pranto? Não há em ti rei? pereceu o teu conselheiro, de modo que se apoderaram de ti dores, como da que está de parto,' },
      { v: 10, en: 'Be in pain, and labor to give birth, daughter of Zion, like a woman in travail; for now you will go out of the city, and will dwell in the field, and will come even to Babylon. There you will be rescued. There Yahweh will redeem you from the hand of your enemies.', pt: 'Sofre dores e trabalha, ó filha de Sião, como a que está de parto; porque agora sairás da cidade, e morarás no campo, e virás até Babilônia. Ali, porém serás livrada; ali te remirá o Senhor da mão de teus inimigos.' },
      { v: 11, en: 'Now many nations have assembled against you, that say, “Let her be defiled, and let our eye gloat over Zion.”', pt: 'Agora se congregaram muitas nações contra ti, que dizem: Seja ela profanada, e vejam o nossos olhos o seu desejo sobre Sião.' },
      { v: 12, en: 'But they don’t know the thoughts of Yahweh, neither do they understand his counsel; for he has gathered them like the sheaves to the threshing floor.', pt: 'Mas, não sabem os pensamentos do Senhor, nem entendem o seu conselho; porque as ajuntou como gavelas para dentro da eira.' },
      { v: 13, en: 'Arise and thresh, daughter of Zion; for I will make your horn iron, and I will make your hoofs brass; and you will beat in pieces many peoples: and I will devote their gain to Yahweh, and their substance to the Lord of the whole earth.', pt: 'Levanta-te, e debulha, ó filha de Sião, porque eu farei de ferro o teu chifre, e de bronze as tuas unhas; e esmiuçarás a muitos povos; e dedicarás o seu ganho ao Senhor, e os seus bens ao Senhor de toda a terra.' },
    ],
    5: [
      { v: 1, en: 'Now you shall gather yourself in troops, daughter of troops. He has laid siege against us. They will strike the judge of Israel with a rod on the cheek.', pt: 'Agora, ajunta-te em tropas, ó filha de tropas; pôr-se-á cerco contra nós; ferirão com a vara no queixo ao juiz de Israel.' },
      { v: 2, en: 'But you, Bethlehem Ephrathah, being small among the clans of Judah, out of you one will come out to me that is to be ruler in Israel; whose goings out are from of old, from ancient times.', pt: 'Mas tu, Belém Efrata, posto que pequena para estar entre os milhares de Judá, de ti é que me sairá aquele que há de reinar em Israel, e cujas saídas são desde os tempos antigos, desde os dias da eternidade.' },
      { v: 3, en: 'Therefore he will abandon them until the time that she who is in labor gives birth. Then the rest of his brothers will return to the children of Israel.', pt: 'Portanto os entregará até o tempo em que a que está de parto tiver dado à luz; então o resto de seus irmãos voltará aos filhos de Israel.' },
      { v: 4, en: 'He shall stand, and shall shepherd in the strength of Yahweh, in the majesty of the name of Yahweh his God: and they will live, for then he will be great to the ends of the earth.', pt: 'E ele permanecerá, e apascentará o povo na força do Senhor, na excelência do nome do Senhor seu Deus; e eles permanecerão, porque agora ele será grande até os fins da terra.' },
      { v: 5, en: 'He will be our peace when Assyria invades our land, and when he marches through our fortresses, then we will raise against him seven shepherds, and eight leaders of men.', pt: 'E este será a nossa paz. Quando a Assíria entrar em nossa terra, e quando pisar em nossos palácios, então suscitaremos contra ela sete pastores e oito príncipes dentre os homems.' },
      { v: 6, en: 'They will rule the land of Assyria with the sword, and the land of Nimrod in its gates. He will deliver us from the Assyrian, when he invades our land, and when he marches within our border.', pt: 'Esses consumirão a terra da Assíria à espada, e a terra de Ninrode nas suas entradas. Assim ele nos livrará da Assíria, quando entrar em nossa terra, e quando calcar os nossos termos.' },
      { v: 7, en: 'The remnant of Jacob will be among many peoples, like dew from Yahweh, like showers on the grass, that don’t wait for man, nor wait for the sons of men.', pt: 'E o resto de Jacó estará no meio de muitos povos, como orvalho da parte do Senhor, como chuvisco sobre a erva, que não espera pelo homem, nem aguarda filpios de homens.' },
      { v: 8, en: 'The remnant of Jacob will be among the nations, among many peoples, like a lion among the animals of the forest, like a young lion among the flocks of sheep; who, if he goes through, treads down and tears in pieces, and there is no one to deliver.', pt: 'Tambem o resto de Jacó estará entre as nações, no meio de muitos povos, como um leão entre os animais do bosque, como um leão novo entre os rebanhos de ovelhas, o qual, quando passar, as pisará e despedaçará, sem que haja quem as livre.' },
      { v: 9, en: 'Let your hand be lifted up above your adversaries, and let all of your enemies be cut off.', pt: 'A tua mão será exaltada sobre os teus adversários e serão exterminados todos os seus inimigos.' },
      { v: 10, en: '“It will happen in that day”, says Yahweh, “that I will cut off your horses out from among you, and will destroy your chariots.', pt: 'Naquele dia, diz o Senhor, exterminarei do meio de ti os teus cavalos, e destrurei os teus carros;' },
      { v: 11, en: 'I will cut off the cities of your land, and will tear down all your strongholds.', pt: 'destruirei as cidade da tua terra, e derribarei todas as tuas fortalezas.' },
      { v: 12, en: 'I will destroy witchcraft from your hand; and you shall have no soothsayers.', pt: 'Tirarei as feitiçarias da tua mão, e não terás adivinhadores;' },
      { v: 13, en: 'I will cut off your engraved images and your pillars out from among you; and you shall no more worship the work of your hands.', pt: 'arrancarei do meio de ti as tuas imagens esculpidas e as tuas colunas; e nao adorarás mais a obra das tuas mãos.' },
      { v: 14, en: 'I will uproot your Asherah poles out from among you; and I will destroy your cities.', pt: 'Do meio de ti arrancarei os teus aserins, e destruirei as tuas cidades.' },
      { v: 15, en: 'I will execute vengeance in anger, and wrath on the nations that didn’t listen.”', pt: 'E com ira e com furor exercerei vingança sobre as nações que não obedeceram.' },
    ],
    6: [
      { v: 1, en: 'Listen now to what Yahweh says: “Arise, plead your case before the mountains, and let the hills hear what you have to say.', pt: 'Ouvi agora o que diz o Senhor: Levanta-te, contende perante os montes, e ouçam os outeiros a tua voz.' },
      { v: 2, en: 'Hear, you mountains, Yahweh’s controversy, and you enduring foundations of the earth; for Yahweh has a controversy with his people, and he will contend with Israel.', pt: 'Ouvi, montes, a demanda do Senhor, e vós, fundamentos duradouros da terra; porque o Senhor tem uma demanda com o seu povo e com Israel entrará em juízo.' },
      { v: 3, en: 'My people, what have I done to you? How have I burdened you? Answer me!', pt: 'ç povo meu, que é que te tenho feito? e em que te enfadei? testifica contra mim.' },
      { v: 4, en: 'For I brought you up out of the land of Egypt, and redeemed you out of the house of bondage. I sent before you Moses, Aaron, and Miriam.', pt: 'Pois te fiz subir da terra do Egito, e da casa da servidão te remi; e enviei adiante de ti a Moisés, Arão e Miriã.' },
      { v: 5, en: 'My people, remember now what Balak king of Moab devised, and what Balaam the son of Beor answered him from Shittim to Gilgal, that you may know the righteous acts of Yahweh.”', pt: 'Povo meu, lembra-te agora da consulta de Balaque, rei de Meabe, e do que lhe respondeu Balaão, filho de Beor, e do que sucedeu desde Sitini até Gilgal, para que conheças as justiças do Senhor.' },
      { v: 6, en: 'How shall I come before Yahweh, and bow myself before the exalted God? Shall I come before him with burnt offerings, with calves a year old?', pt: 'Com que me apresentarei diante do Senhor, e me prostrarei perante o Deus excelso? Apresentar-me-ei diante dele com holocausto, com bezerros de um ano?' },
      { v: 7, en: 'Will Yahweh be pleased with thousands of rams? With tens of thousands of rivers of oil? Shall I give my firstborn for my disobedience? The fruit of my body for the sin of my soul?', pt: 'Agradar-se-á o Senhor de milhares de carneiros, ou de miríades de ribeiros de azeite? Darei o meu primogênito pela minha transgressão, o fruto das minhas entranhas pelo pecado da minha alma?' },
      { v: 8, en: 'He has shown you, O man, what is good. What does Yahweh require of you, but to act justly, to love mercy, and to walk humbly with your God?', pt: 'Ele te declarou, ó homem, o que é bom; e que é o que o Senhor requer de ti, senão que pratiques a justiça, e ames a benevolência, e andes humildemente com o teu Deus?' },
      { v: 9, en: 'Yahweh’s voice calls to the city, and wisdom sees your name: “Listen to the rod, and he who appointed it.', pt: 'A voz do Senhor clama à cidade, e o que é sábio temerá o teu nome. Escutai a vara, e quem a ordenou.' },
      { v: 10, en: 'Are there yet treasures of wickedness in the house of the wicked, and a short ephah that is accursed?', pt: 'Porventura ainda há na casa do impio tesouros de impiedade? e a efa desfalcada, que é detestável?' },
      { v: 11, en: 'Shall I be pure with dishonest scales, and with a bag of deceitful weights?', pt: 'Justificerei ao que tem balanças falsas, e uma bolsa de pesos enganosos?' },
      { v: 12, en: 'Her rich men are full of violence, her inhabitants speak lies, and their tongue is deceitful in their speech.', pt: 'Pois os ricos da cidade estão cheios de violência, e os seus habitantes falam mentiras, e a lingua deles é enganosa na sua boca.' },
      { v: 13, en: 'Therefore I also have struck you with a grievous wound. I have made you desolate because of your sins.', pt: 'Assim eu tambem te enfraquecerei, ferindo-te e assolando-te, por causa dos teus pecados.' },
      { v: 14, en: 'You shall eat, but not be satisfied. Your humiliation will be within you. You will store up, but not save; and that which you save I will give up to the sword.', pt: 'Tu comerás, mas não te fartarás; e a tua fome estará sempre contigo; removerás os teus bens, mas nada livrarás; e aquilo que livrares, eu o entregarei à espada.' },
      { v: 15, en: 'You will sow, but won’t reap. You will tread the olives, but won’t anoint yourself with oil; and crush grapes, but won’t drink the wine.', pt: 'Tu semearás, mas não segarás; pisarás a azeitona, mas não te ungirás de azeite; e pisarás a vindima, mas não beberás o vinho.' },
      { v: 16, en: 'For the statutes of Omri are kept, and all the works of Ahab’s house. You walk in their counsels, that I may make you a ruin, and her inhabitants a hissing; And you will bear the reproach of my people.”', pt: 'Porque se observam os estatutos de Onri, e todas as obras da casa de Acabe, e vós andais nos conselhos deles; para que eu faça de ti uma desolação, e dos seus habitantes um assobio. Assim trareis sobre vós o opróbrio do meu povo.' },
    ],
    7: [
      { v: 1, en: 'Misery is mine! Indeed, I am like one who gathers the summer fruits, as gleanings of the vineyard: There is no cluster of grapes to eat. My soul desires to eat the early fig.', pt: 'Ai de mim! porque estou feito como quando são colhidas as frutas do verão, como os rabiscos da vindima; não há cacho de uvas para comer, nem figo temporão que a minha alma deseja.' },
      { v: 2, en: 'The godly man has perished out of the earth, and there is no one upright among men. They all lie in wait for blood; every man hunts his brother with a net.', pt: 'Pereceu da terra o homem piedoso; e entre os homens não há um que seja reto; todos armam ciladas para sangue; caça cada um a seu irmão com uma rede.' },
      { v: 3, en: 'Their hands are on that which is evil to do it diligently. The ruler and judge ask for a bribe; and the powerful man dictates the evil desire of his soul. Thus they conspire together.', pt: 'As suas mãos estão sobre o mal para o fazerem diligentemente; o príncipe e o juiz exigem a peita, e o grande manifesta o desejo mau da sua alma; e assim todos eles tecem o mal.' },
      { v: 4, en: 'The best of them is like a brier. The most upright is worse than a thorn hedge. The day of your watchmen, even your visitation, has come; now is the time of their confusion.', pt: 'O melhor deles é como um espinho; o mais reto é pior do que uma sebe de espinhos. Veio o dia dos seus vigias, a saber, a sua punição; agora começará a sua confusao.' },
      { v: 5, en: 'Don’t trust in a neighbor. Don’t put confidence in a friend. With the woman lying in your embrace, be careful of the words of your mouth!', pt: 'Não creiais no amigo, nem confieis no companheiro; guarda as portas da tua boca daquela que repousa no teu seio.' },
      { v: 6, en: 'For the son dishonors the father, the daughter rises up against her mother, the daughter-in-law against her mother-in-law; a man’s enemies are the men of his own house.', pt: 'Pois o filho despreza o pai, a filha se levanta contra a mãe, a nora contra a sogra; os inimigos do homem são os da própria casa.' },
      { v: 7, en: 'But as for me, I will look to Yahweh. I will wait for the God of my salvation. My God will hear me.', pt: 'Eu, porém, confiarei no Senhor; esperarei no Deus da minha salvação. O meu Deus me ouvirá.' },
      { v: 8, en: 'Don’t rejoice against me, my enemy. When I fall, I will arise. When I sit in darkness, Yahweh will be a light to me.', pt: 'Não te alegres, inimiga minha, a meu respeito; quando eu cair, levantar-me-ei; quando me sentar nas trevas, o Senhor será a minha luz.' },
      { v: 9, en: 'I will bear the indignation of Yahweh, because I have sinned against him, until he pleads my case, and executes judgment for me. He will bring me out to the light. I will see his righteousness.', pt: 'Sofrerei a indignação do Senhor, porque tenho pecado contra ele; até que ele julgue a minha causa, e execute o meu direito. Ele me tirará para a luz, e eu verei a sua justiça.' },
      { v: 10, en: 'Then my enemy will see it, and shame will cover her who said to me, where is Yahweh your God? Then my enemy will see me and will cover her shame. Now she will be trodden down like the mire of the streets.', pt: 'E a minha inimiga verá isso, e cobrila-á a confusão, a ela que me disse: Onde está o Senhor teu Deus? Os meus olhos a contemplarão; agora ela será pisada como a lama das ruas.' },
      { v: 11, en: 'A day to build your walls— In that day, he will extend your boundary.', pt: 'É dia de reedificar os teus muros! Naquele dia será dilatado grandemente o teu termo.' },
      { v: 12, en: 'In that day they will come to you from Assyria and the cities of Egypt, and from Egypt even to the River, and from sea to sea, and mountain to mountain.', pt: 'Naquele dia virão a ti da Assíria e das cidades do Egito, e do Egito até o Rio, e de mar a mar, e de montanha a montanha.' },
      { v: 13, en: 'Yet the land will be desolate because of those who dwell therein, for the fruit of their doings.', pt: 'Mas a terra será entregue à desolação por causa dos seus moradores, por causa do fruto das suas obras.' },
      { v: 14, en: 'Shepherd your people with your staff, the flock of your heritage, who dwell by themselves in a forest, in the middle of fertile pasture land, let them feed; in Bashan and Gilead, as in the days of old.', pt: 'Apascenta com a tua vara o teu povo, o rebanho da tua herança, que habita a sós no bosque, no meio do Carmelo; apascentem-se em Basã e Gileade, como nos dias antigos.' },
      { v: 15, en: '“As in the days of your coming out of the land of Egypt, I will show them marvelous things.”', pt: 'Eu lhes mostrarei maravilhas, como nos dias da tua saída da terra do Egito.' },
      { v: 16, en: 'The nations will see and be ashamed of all their might. They will lay their hand on their mouth. Their ears will be deaf.', pt: 'As nações o verão, e envergonhar-se-ão, por causa de todo o seu poder; porão a mão sobre a boca, e os seus ouvidos ficarão surdos.' },
      { v: 17, en: 'They will lick the dust like a serpent. Like crawling things of the earth they shall come trembling out of their dens. They will come with fear to Yahweh our God, and will be afraid because of you.', pt: 'Lamberão o pó como serpentes; como répteis da terra, tremendo, sairão dos seus esconderijos; com pavor virão ao Senhor nosso Deus, e terão medo de ti.' },
      { v: 18, en: 'Who is a God like you, who pardons iniquity, and passes over the disobedience of the remnant of his heritage? He doesn’t retain his anger forever, because he delights in loving kindness.', pt: 'Quem é Deus semelhante a ti, que perdoas a iniqüidade, e que te esqueces da transgressão do resto da tua herança? O Senhor não retém a sua ira para sempre, porque ele se deleita na benignidade.' },
      { v: 19, en: 'He will again have compassion on us. He will tread our iniquities under foot; and you will cast all their sins into the depths of the sea.', pt: 'Tornará a apiedar-se de nós; pisará aos pés as nossas iniqüidades. Tu lançarás todos os nossos pecados nas profundezas do mar.' },
      { v: 20, en: 'You will give truth to Jacob, and mercy to Abraham, as you have sworn to our fathers from the days of old.', pt: 'Mostrarás a Jacó a fidelidade, e a Abraão a benignidade, conforme juraste a nossos pais desde os dias antigos.' },
    ],
  },
};

export default book;
